import{_ as t,o as e,c as a,a2 as r}from"./chunks/framework.Crpw6aS5.js";const n=JSON.parse('{"title":"2008年 · 金融危机","description":"","frontmatter":{},"headers":[],"relativePath":"05_quotes/by-year/2008年.md","filePath":"05_quotes/by-year/2008年.md"}'),u={name:"05_quotes/by-year/2008年.md"};function l(q,o,c,p,h,s){return e(),a("div",null,[...o[0]||(o[0]=[r('<h1 id="_2008年-·-金融危机" tabindex="-1">2008年 · 金融危机 <a class="header-anchor" href="#_2008年-·-金融危机" aria-label="Permalink to &quot;2008年 · 金融危机&quot;">​</a></h1><blockquote><p>&quot;恐惧会传染。金融系统崩溃往往不是因为基本面有多差，而是因为恐惧本身。&quot;——巴菲特</p></blockquote><p>本页收录2008年<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>年报中的经典语录，这是巴菲特执笔五十年来，最具历史意义的一封信。</p><hr><h2 id="核心金句" tabindex="-1">核心金句 <a class="header-anchor" href="#核心金句" aria-label="Permalink to &quot;核心金句&quot;">​</a></h2><blockquote><p>&quot;恐惧会传染。金融系统崩溃往往不是因为基本面有多差，而是因为恐惧本身。当所有人都开始恐惧时，恐惧本身就成了最大的风险。&quot;</p></blockquote><blockquote><p>&quot;我们在2008年9月写给《纽约时报》的文章里说：买入美国股票。这看起来像是在逆势冒险，但查理和我知道，这是我们一生中最好的买入时机之一。&quot;</p></blockquote><blockquote><p>&quot;我们不借款进行杠杆收购。如果我们不借钱，就不会被迫在不利时刻卖出。这是风险管理的根本，不是保守主义。&quot;</p></blockquote><blockquote><p>&quot;衍生品是大规模毁灭性金融武器。我们在1998年亲眼看到长期资本管理公司的崩溃——那些拥有最聪明数学家的人，因为杠杆和衍生品，最终毁掉了自己。&quot;</p></blockquote><blockquote><p>&quot;潮水退去时，我们手里还有资金，可以买到打折的资产。这就是不亏钱的意义——在危机中，你反而变得更有购买力。&quot;</p></blockquote><blockquote><p>&quot;1974年我说这是投资的最好时机，2008年我再次说同样的话。历史不会简单重复，但周期的本质不会改变。&quot;</p></blockquote><blockquote><p>&quot;不要做空美国。这是伯克希尔一切信念的起点。&quot;</p></blockquote><hr><h2 id="本年背景" tabindex="-1">本年背景 <a class="header-anchor" href="#本年背景" aria-label="Permalink to &quot;本年背景&quot;">​</a></h2><p>2008年9月，雷曼兄弟倒闭，全球金融体系陷入恐慌。巴菲特在《纽约时报》发表署名文章《我在买美国股票》，成为这场危机中最著名的逆向投资宣言。同年，伯克希尔斥资150亿美元买入高盛优先股（股息率10%），并大规模投资其他优质资产。这些交易后来为伯克希尔带来了超额回报。</p><hr><h2 id="深入阅读" tabindex="-1">深入阅读 <a class="header-anchor" href="#深入阅读" aria-label="Permalink to &quot;深入阅读&quot;">​</a></h2><p><a href="/search.html?q=→ 原文翻译">01_letters/2008年/翻译</a> · <a href="/search.html?q=→ 核心总结">01_letters/2008年/核心总结</a></p>',18)])])}const i=t(u,[["render",l]]);export{n as __pageData,i as default};
